        owner = msg.sender;
    }

    function lockContract() external onlyOwner {
        locked = true;
    }

    function addCandidate(string memory name) external onlyOwner notLocked {
        candidates.push(Candidate(name, 0));
        emit CandidateAdded(candidates.length - 1, name);
    }

    function grantVotingRights(address voter) external onlyOwner notLocked {
        require(!voters[voter], "Voting rights already granted");
        voters[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return voters[voter];
    }

    function candidateCount() public view returns (uint256) {
        return candidates.length;
    }

    function candidateNames(uint256 index) public view returns (string memory) {
        require(index < candidates.length, "Invalid candidate index");
        return candidates[index].name;
    }

    function candidateVotes(uint256 index) public view returns (uint256) {
        require(index < candidates.length, "Invalid candidate index");
        return candidates[index].votes;
    }

    function vote(uint256 candidateId) external {
        require(hasVotingRights(msg.sender), "No voting rights");
        require(!voted[msg.sender], "Already voted");
        require(candidateId < candidates.length, "Invalid candidate ID");

        candidates[candidateId].votes++;
        voted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }
}
